import{_ as n,C as s,c as B,o,R as E,b as A,k as t,w as r,a as e,G as i,a1 as d}from"./chunks/framework.Dxoqk0BT.js";const u="/img/ai-1.png",h="/img/ai-2.png",D=JSON.parse('{"title":"AI 在生产环境中的提效实践","description":"","frontmatter":{},"headers":[],"relativePath":"ai/3.md","filePath":"ai/3.md"}'),C={name:"ai/3.md"};function b(g,a,m,c,p,I){const l=s("Mermaid");return o(),B("div",null,[a[4]||(a[4]=E('<h1 id="ai-在生产环境中的提效实践" tabindex="-1">AI 在生产环境中的提效实践 <a class="header-anchor" href="#ai-在生产环境中的提效实践" aria-label="Permalink to &quot;AI 在生产环境中的提效实践&quot;">​</a></h1><p>在实际项目中,我们将 AI 深度集成到软件开发生命周期（SDLC）的各个环节,构建了一套 <strong>&quot;AI 工作流&quot;</strong> 自动化方案。核心理念很简单：让 AI 处理重复的、机械化的工作,让开发者专注于核心业务逻辑和创新。</p><h2 id="背景与目标" tabindex="-1">背景与目标 <a class="header-anchor" href="#背景与目标" aria-label="Permalink to &quot;背景与目标&quot;">​</a></h2><h3 id="面临的问题" tabindex="-1">面临的问题 <a class="header-anchor" href="#面临的问题" aria-label="Permalink to &quot;面临的问题&quot;">​</a></h3><p>在实际工作中,我们发现了几个明显的痛点：</p><ul><li><strong>工具泛滥</strong>：市面上 AI 工具很多,但缺乏与团队上下文结合的完整方案</li><li><strong>知识孤岛</strong>：团队规范文档很完备,但没有融入开发流程,查阅成本高</li><li><strong>效率瓶颈</strong>：Code Review、研发自测、接口文档更新等环节消耗大量时间</li></ul><h3 id="解决思路" tabindex="-1">解决思路 <a class="header-anchor" href="#解决思路" aria-label="Permalink to &quot;解决思路&quot;">​</a></h3><ul><li><strong>流程智能化</strong>：让研发流程向 AI 化转变</li><li><strong>效率提升</strong>：用 AI 减少非核心事务的人力消耗,聚焦业务创新</li></ul><h2 id="整体思路与-ai-工作流" tabindex="-1">整体思路与 AI 工作流 <a class="header-anchor" href="#整体思路与-ai-工作流" aria-label="Permalink to &quot;整体思路与 AI 工作流&quot;">​</a></h2><p>我们将研发链路拆解,在每个阶段注入 AI 能力,将传统的线性流程转变为 AI 加持的并行自动化流程。</p>',10)),(o(),A(d,null,{default:r(()=>[i(l,{id:"mermaid-53",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20subgraph%20Traditional%20%5B%E4%BC%A0%E7%BB%9F%E7%A0%94%E5%8F%91%E6%B5%81%E7%A8%8B%5D%0A%20%20%20%20%20%20%20%20direction%20LR%0A%20%20%20%20%20%20%20%20A1%5B%E9%9C%80%E6%B1%82%E8%AF%84%E5%AE%A1%5D%20--%3E%20A2%5B%E6%8A%80%E6%9C%AF%E8%AE%BE%E8%AE%A1%5D%20--%3E%20A3%5B%E7%BC%96%E7%A0%81%5D%20--%3E%20A4%5B%E6%B5%8B%E8%AF%95%5D%20--%3E%20A5%5B%E9%83%A8%E7%BD%B2%E8%BF%90%E7%BB%B4%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20AIPowered%20%5BAI%E5%8A%A0%E6%8C%81%E7%A0%94%E5%8F%91%E6%B5%81%E7%A8%8B%5D%0A%20%20%20%20%20%20%20%20direction%20LR%0A%20%20%20%20%20%20%20%20B1%5BAI-CafeDocs%3Cbr%3E%E9%9C%80%E6%B1%82%2F%E5%8E%9F%E5%9E%8B%E7%94%9F%E6%88%90%5D%20--%3E%20B2%5BAI-Docs%3Cbr%3E%E9%9C%80%E6%B1%82%E8%BD%AC%E6%8A%80%E6%9C%AF%E6%96%87%E6%A1%A3%5D%20--%3E%20B3%5BAI-DocsCoding%3Cbr%3E%E7%94%9F%E6%88%90%E5%9F%BA%E7%A1%80%E4%BB%A3%E7%A0%81%5D%20--%3E%20B4%5BAI-Coding%3Cbr%3E%E8%A7%84%E8%8C%83%E7%BC%96%E7%A0%81%5D%20--%3E%20B5%5BAI-API%3Cbr%3E%E6%8E%A5%E5%8F%A3%E6%96%87%E6%A1%A3%E5%90%8C%E6%AD%A5%5D%0A%0A%20%20%20%20%20%20%20%20B3%20%26%20B4%20--%3E%20B6%5BAI-CR%3Cbr%3E%E8%87%AA%E5%8A%A8%E5%8C%96%E4%BB%A3%E7%A0%81%E5%AE%A1%E6%9F%A5%5D%0A%20%20%20%20%20%20%20%20B4%20--%3E%20B7%5BAI-Develops%3Cbr%3E%E8%B5%8B%E8%83%BD%E6%B5%8B%E8%AF%95%2F%E8%BF%90%E7%BB%B4%5D%0A%20%20%20%20end%0A%0A%20%20%20%20Traditional%20-.-%3E%20AIPowered%0A"})]),fallback:r(()=>[...a[0]||(a[0]=[e(" Loading... ",-1)])]),_:1})),a[5]||(a[5]=E('<h2 id="关键技术实践" tabindex="-1">关键技术实践 <a class="header-anchor" href="#关键技术实践" aria-label="Permalink to &quot;关键技术实践&quot;">​</a></h2><p>在开发阶段（AI-Coding）,我们重点实践了三个核心技术方案。</p><h3 id="_1-rule-规则-的精妙运用" tabindex="-1">1. Rule（规则）的精妙运用 <a class="header-anchor" href="#_1-rule-规则-的精妙运用" aria-label="Permalink to &quot;1. Rule（规则）的精妙运用&quot;">​</a></h3><p>Rule 是 <strong>&quot;连接开发者意图与 AI 代码生成行为的关键桥梁&quot;</strong>。它将项目规范、编码标准等上下文信息持久化地注入到每次 AI 请求的提示词（Prompt）中,解决大模型缺乏持久记忆的问题。</p><h4 id="rule-的五层分级策略" tabindex="-1">Rule 的五层分级策略 <a class="header-anchor" href="#rule-的五层分级策略" aria-label="Permalink to &quot;Rule 的五层分级策略&quot;">​</a></h4><table><thead><tr><th>层级</th><th>名称</th><th>位置</th><th>范围</th><th>内容</th><th>优先级</th></tr></thead><tbody><tr><td>第一层</td><td>IDE 全局层</td><td>User Rules</td><td>所有项目</td><td>个人编码风格偏好</td><td>N/A</td></tr><tr><td>第二层</td><td>项目基础层<br>(Always Rules)</td><td><code>.xx/rules/always/</code></td><td>整个项目强制遵循</td><td>技术栈、核心原则、基础规范</td><td>10 (最高)</td></tr><tr><td>第三层</td><td>自动匹配层<br>(Auto Rules)</td><td><code>.xx/rules/auto/</code></td><td>特定文件/目录</td><td>模块专门的开发规范</td><td>6-9</td></tr><tr><td>第四层</td><td>智能推荐层<br>(Agent Rules)</td><td><code>.xx/rules/agent/</code></td><td>AI 智能判断</td><td>优化建议和最佳实践</td><td>5</td></tr><tr><td>第五层</td><td>手动调用层<br>(Manual Rules)</td><td><code>.xx/rules/manual/</code></td><td>手动调用</td><td>完整的项目或模块模板</td><td>3-4</td></tr></tbody></table><h4 id="rule-优先级冲突解决机制" tabindex="-1">Rule 优先级冲突解决机制 <a class="header-anchor" href="#rule-优先级冲突解决机制" aria-label="Permalink to &quot;Rule 优先级冲突解决机制&quot;">​</a></h4>',7)),(o(),A(d,null,{default:r(()=>[i(l,{id:"mermaid-198",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20P10%5B%E4%BC%98%E5%85%88%E7%BA%A7%2010%3Cbr%3EAlways%20Rules%5D%20--%3E%20W%5B%E8%A7%84%E5%88%99%E5%86%B2%E7%AA%81%5D%0A%20%20%20%20P89%5B%E4%BC%98%E5%85%88%E7%BA%A7%208-9%3Cbr%3EAuto%20Rules%EF%BC%88%E6%A0%B8%E5%BF%83%EF%BC%89%5D%20--%3E%20W%0A%20%20%20%20P67%5B%E4%BC%98%E5%85%88%E7%BA%A7%206-7%3Cbr%3EAuto%20Rules%EF%BC%88%E8%BE%85%E5%8A%A9%EF%BC%89%5D%20--%3E%20W%0A%20%20%20%20P5%5B%E4%BC%98%E5%85%88%E7%BA%A7%205%3Cbr%3EAgent%20Rules%5D%20--%3E%20W%0A%20%20%20%20P34%5B%E4%BC%98%E5%85%88%E7%BA%A7%203-4%3Cbr%3EManual%20Rules%5D%20--%3E%20W%0A%0A%20%20%20%20W%20--%3E%20R%5B%E9%AB%98%E4%BC%98%E5%85%88%E7%BA%A7%E8%A7%84%E5%88%99%E8%A6%86%E7%9B%96%3Cbr%3E%E4%BD%8E%E4%BC%98%E5%85%88%E7%BA%A7%E8%A7%84%E5%88%99%E7%9A%84%E5%86%B2%E7%AA%81%E9%83%A8%E5%88%86%5D%0A"})]),fallback:r(()=>[...a[1]||(a[1]=[e(" Loading... ",-1)])]),_:1})),a[6]||(a[6]=E('<h4 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to &quot;最佳实践&quot;">​</a></h4><ul><li><strong>内容优化</strong>：用简洁的要点列表（20-30 行）代替冗长的代码示例和解释。</li><li><strong>精确匹配</strong>：使用 globs 模式精确匹配特定目录（如 <code>internal/handler/**/*.go</code>），避免过于宽泛（如 <code>**/*.go</code>）。</li></ul><h3 id="_2-记忆库-memory-bank" tabindex="-1">2. 记忆库 (Memory Bank) <a class="header-anchor" href="#_2-记忆库-memory-bank" aria-label="Permalink to &quot;2. 记忆库 (Memory Bank)&quot;">​</a></h3><p>为了解决 AI 在复杂项目中 <strong>&quot;上下文丢失&quot;</strong> 和 <strong>&quot;对业务逻辑一知半解&quot;</strong> 的痛点,我们引入了记忆库模式。</p><ul><li><strong>本质</strong>：一种特殊的 Rule,将项目的重要上下文、历史决策、业务逻辑总结并存储,强制 AI 在每次交互时阅读,保持对话连续性</li><li><strong>与 IDE 长期记忆的区别</strong>： <ul><li><strong>记忆库</strong>：公共的、项目级别的记忆,对所有协作者一致</li><li><strong>IDE 长期记忆</strong>：私人的、开发者级别的记忆,仅限个人使用</li></ul></li></ul><h3 id="_3-mcp-server-模型上下文协议" tabindex="-1">3. MCP Server（模型上下文协议） <a class="header-anchor" href="#_3-mcp-server-模型上下文协议" aria-label="Permalink to &quot;3. MCP Server（模型上下文协议）&quot;">​</a></h3><p><strong>MCP（Model Context Protocol）</strong> 是一个重要的技术实践点。它为大模型和外部世界（数据、工具、服务）提供统一的通信框架。</p><h4 id="mcp-核心架构" tabindex="-1">MCP 核心架构 <a class="header-anchor" href="#mcp-核心架构" aria-label="Permalink to &quot;MCP 核心架构&quot;">​</a></h4>',8)),(o(),A(d,null,{default:r(()=>[i(l,{id:"mermaid-253",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20H%5BHost%E4%B8%BB%E6%9C%BA%3Cbr%3Ee.g.%20Cursor%20IDE%5D%20%3C--%3E%20C%5BClient%E5%AE%A2%E6%88%B7%E7%AB%AF%3Cbr%3EAI%E4%B8%8EServer%E7%9A%84%E6%A1%A5%E6%A2%81%5D%0A%20%20%20%20C%20%3C--%3E%20S%5BServer%E6%9C%8D%E5%8A%A1%E5%99%A8%3Cbr%3Ee.g.%20%E6%95%B0%E6%8D%AE%E5%BA%93%2F%E6%90%9C%E7%B4%A2%E5%BC%95%E6%93%8E%E5%B7%A5%E5%85%B7%5D%0A%0A%20%20%20%20H%20--%20%E7%94%A8%E6%88%B7%E6%8C%87%E4%BB%A4%2FAI%E5%93%8D%E5%BA%94%20--%3E%20C%0A%20%20%20%20C%20--%20%E5%B7%A5%E5%85%B7%E8%B0%83%E7%94%A8%E8%AF%B7%E6%B1%82%20--%3E%20S%0A%20%20%20%20S%20--%20%E5%B7%A5%E5%85%B7%E8%B0%83%E7%94%A8%E7%BB%93%E6%9E%9C%20--%3E%20C%0A"})]),fallback:r(()=>[...a[2]||(a[2]=[e(" Loading... ",-1)])]),_:1})),a[7]||(a[7]=E('<h4 id="在开发中的具体应用" tabindex="-1">在开发中的具体应用 <a class="header-anchor" href="#在开发中的具体应用" aria-label="Permalink to &quot;在开发中的具体应用&quot;">​</a></h4><h5 id="用法一-接入搜索引擎-mcp" tabindex="-1">用法一：接入搜索引擎 MCP <a class="header-anchor" href="#用法一-接入搜索引擎-mcp" aria-label="Permalink to &quot;用法一：接入搜索引擎 MCP&quot;">​</a></h5><p>无需切换浏览器,在 IDE 内让 AI 搜索技术问题、知识点,并直接总结答案。</p><h5 id="用法二-接入数据库和运维工具-client" tabindex="-1">用法二：接入数据库和运维工具 Client <a class="header-anchor" href="#用法二-接入数据库和运维工具-client" aria-label="Permalink to &quot;用法二：接入数据库和运维工具 Client&quot;">​</a></h5><ul><li><strong>自然语言操作数据库</strong>：用口语化指令（如&quot;查询用户张三最近一笔订单&quot;）操作 MySQL、Redis,无需写 SQL</li><li><strong>自然语言操作基础设施</strong>：通过 kubectl、GCP 等 Client 管理云资源</li></ul><blockquote><p>⚠️ <strong>安全提醒</strong>：严禁在开发环境使用线上账号密码,安全第一。</p></blockquote><h2 id="全链路-ai-应用" tabindex="-1">全链路 AI 应用 <a class="header-anchor" href="#全链路-ai-应用" aria-label="Permalink to &quot;全链路 AI 应用&quot;">​</a></h2><p>原本研发链路:</p><p><img src="'+u+'" alt="原本研发链路"></p><p>AI 加持研发流程</p><p><img src="'+h+'" alt="AI加持研发流程"></p><h3 id="需求阶段-ai-cafedocs-ai-docscoding" tabindex="-1">需求阶段 (AI-CafeDocs &amp; AI-DocsCoding) <a class="header-anchor" href="#需求阶段-ai-cafedocs-ai-docscoding" aria-label="Permalink to &quot;需求阶段 (AI-CafeDocs &amp; AI-DocsCoding)&quot;">​</a></h3><ul><li><strong>流程</strong>：需求文档 → 低代码平台 Aisuda → 大模型 → 技术文档(Markdown)</li><li><strong>价值</strong>：生成初版技术文档和 API 设计,人工只需核对和补充核心业务逻辑,角色转变为&quot;驱动者/验收者&quot;。</li></ul><h3 id="集成阶段-ai-cr" tabindex="-1">集成阶段 (AI-CR) <a class="header-anchor" href="#集成阶段-ai-cr" aria-label="Permalink to &quot;集成阶段 (AI-CR)&quot;">​</a></h3><ul><li><strong>痛点</strong>：CR 耗时、沟通低效、重复劳动</li><li><strong>方案</strong>：引入 AI 自动化审查,提前规避基础规范、常见漏洞问题,让人类专家专注于关键业务逻辑和架构审查。</li></ul><h3 id="运维阶段-ai-develops" tabindex="-1">运维阶段 (AI-Develops) <a class="header-anchor" href="#运维阶段-ai-develops" aria-label="Permalink to &quot;运维阶段 (AI-Develops)&quot;">​</a></h3><ul><li><strong>痛点</strong>：告警数量多,存在&quot;方向壁垒&quot;和&quot;年限壁垒&quot;,故障排查效率低</li><li><strong>方案</strong>：构建智能化应急诊断系统,通过 AI 自动分析、诊断甚至修复告警,大幅减少平均修复时间（MTTR）。</li></ul><h2 id="核心思想与哲学" tabindex="-1">核心思想与哲学 <a class="header-anchor" href="#核心思想与哲学" aria-label="Permalink to &quot;核心思想与哲学&quot;">​</a></h2><h3 id="_1-递归使用-ai" tabindex="-1">1. 递归使用 AI <a class="header-anchor" href="#_1-递归使用-ai" aria-label="Permalink to &quot;1. 递归使用 AI&quot;">​</a></h3><p>不要一步步指挥 AI,而是将最终目标直接交给 AI,让它自己规划步骤并递归执行。</p><p><strong>例如</strong>：安装 MCP Server 时,只需提供链接,让 AI 自己完成安装、配置、调试的全过程。</p>',21)),(o(),A(d,null,{default:r(()=>[i(l,{id:"mermaid-355",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E7%94%A8%E6%88%B7%E6%8F%90%E5%87%BA%E7%BB%88%E6%9E%81%E7%9B%AE%E6%A0%87%5D%20--%3E%20B%5BAI%E8%A7%84%E5%88%92%E6%AD%A5%E9%AA%A4%E5%B9%B6%E6%89%A7%E8%A1%8C%E7%AC%AC%E4%B8%80%E6%AD%A5%5D%0A%20%20%20%20B%20--%3E%20C%7B%E6%AD%A5%E9%AA%A4%E5%AE%8C%E6%88%90%3F%7D%0A%20%20%20%20C%20--%20%E5%90%A6%20--%3E%20B%0A%20%20%20%20C%20--%20%E6%98%AF%20--%3E%20D%5B%E8%BE%BE%E6%88%90%E7%BB%88%E6%9E%81%E7%9B%AE%E6%A0%87%5D%0A"})]),fallback:r(()=>[...a[3]||(a[3]=[e(" Loading... ",-1)])]),_:1})),a[8]||(a[8]=t("h3",{id:"_2-把-ai-当成真正的工具",tabindex:"-1"},[e("2. 把 AI 当成真正的工具 "),t("a",{class:"header-anchor",href:"#_2-把-ai-当成真正的工具","aria-label":'Permalink to "2. 把 AI 当成真正的工具"'},"​")],-1)),a[9]||(a[9]=t("p",null,[e('遇到任何繁琐、重复、嫌麻烦的"杂活"（如制作 GIF、捞数据、写文档）,都应首先问：'),t("strong",null,'"Can AI Do it?"'),e("。")],-1)),a[10]||(a[10]=t("p",null,"这将许多需要切换上下文的任务,简化为在 IDE 内的一句指令。",-1)),a[11]||(a[11]=t("h2",{id:"总结",tabindex:"-1"},[e("总结 "),t("a",{class:"header-anchor",href:"#总结","aria-label":'Permalink to "总结"'},"​")],-1)),a[12]||(a[12]=t("p",null,"通过这套体系,我们不仅实践了具体技术方案（Rule、MCP、Memory Bank）,更重要的是重构了整个工作流程,建立了新的人机协作范式。",-1)),a[13]||(a[13]=t("p",null,"AI 并非要取代开发者,而是作为一个强大的杠杆,放大开发者的价值,让我们从繁琐劳动中解放出来,专注于真正需要人类智慧和创造力的领域。未来的研发效率提升,关键在于系统地将 AI 能力接入研发流程的各个环节。",-1))])}const f=n(C,[["render",b]]);export{D as __pageData,f as default};
